DROP TABLE IF EXISTS `pjsUpload`;

CREATE TABLE `pjsUpload` (
  `vid_id` int(11) NOT NULL,
  `vid_category` varchar(100),
  `search_category` varchar(100),
  `vid_preacher` varchar(100),
  `vid_title` varchar(500),
  `vid_code` varchar(1000),
  `date` datetime NOT NULL
);

ALTER TABLE `pjsUpload`
  ADD PRIMARY KEY (`vid_id`);

ALTER TABLE `pjsUpload`
  MODIFY `vid_id` int(11) NOT NULL AUTO_INCREMENT, AUTO_INCREMENT=15660;